+        let mut buf = vec![0u8; 10];
+        let err = decode_from_buffer(&mut buf, 4).expect_err("should reject oversize buffer");
+        match err {
+            DirectMuxError::FrameTooLarge { .. } => {}
+            other => panic!("unexpected error: {other}")
+        }
+    }
